mapper.select:
select data_table_name, table_column
from shopping_menu_info
where menu_id = #{menuId}

select *
from ${tableName}
where ${tableColumn} = #{dataId}

select
DISTINCT oi.id, oi.order_id,oi.order_name,oi.data_use,oi.create_time,oi.user_id,oi.real_name,oi.file_num,oi.file_size,oi.order_state,oi.state,oi.order_reason,oi.download_path,ol.identifier
from order_info oi
left join sys_user au
on oi.user_id = au.USER_ID
LEFT JOIN order_list ol
on oi.order_id = ol.order_id


        user_id = #{userId}


        and state = #{state}


        and order_state = #{orderState}


        and oi.create_time >= #{beginTime} and oi.create_time <= #{endTime}


and ol.identifier is not null
order by oi.create_time desc

select *
from ${tableName}
where id = #{dataId}

select count(*)
from order_info oi
where oi.create_time BETWEEN #{beginTime} and #{endTime}

select *
from order_list
where order_id = #{orderId}
  and data_id = #{dataId}
  and identifier = #{identifier}

select sum(file_size) from htht_basis_data_info where 1=1
and tree_id in
#{item.dataId}

select *
from ${tableName}
where tree_id = #{dataId}

select *
from ${tableName}

    ${tableColumn} in

        #{id}

mapper.update:
UPDATE
    order_file_info
set update_time = #{updateTime}
where file_path = #{filePath}

mapper.select:
select di.*,cl.source_file_size,dfi.tif_file_size from htht_dms_sate_data_info as di inner join htht_dms_sate_data_file_info dfi inner join (select dtf.id as source_file_id,dtf.file_name,dtf.file_size as source_file_size from htht_dms_sate_data_task_file dtf where dtf.id in (select source_file_id from htht_dms_sate_data_file_info where data_id in
#{id}
)) cl on di.id= dfi.data_id and dfi.source_file_id = cl.source_file_id

SELECT d.id as d_id, d.file_name as d_file_name, d.space_resolution, d.time_resolution, d.file_size as d_file_size, d.data_type, d.file_type as d_file_type, f.id as f_id, f.file_type as f_file_type, f.file_size as f_file_size, f.file_url, f.file_name as f_file_name FROM `htht_satellite_thematic_data_info` as d ,htht_satellite_thematic_data_file_info as f where d.id=f.data_id and d.id in
#{item}
and f.file_type ='tif' and f.version='0'
